class HashSet:
    def __init__(self, capacity=10):
        self.capacity = capacity
        self.table = [None] * capacity
        self.size = 0

    def __len__(self):
        return self.size

    def __contains__(self, item):
        index = self._hash(item) % self.capacity
        if self.table[index] is not None:
            if isinstance(self.table[index], list):
                return item in self.table[index]
            else:
                return self.table[index] == item
        return False

    def add(self, item):
        if item in self:
            return

        index = self._hash(item) % self.capacity

        if self.table[index] is None:
            self.table[index] = item
        elif isinstance(self.table[index], list):
            self.table[index].append(item)
        else:
            # Collision occurred, create a list to handle it (separate chaining)
            self.table[index] = [self.table[index], item]

        self.size += 1

        # Resize if load factor exceeds a threshold (e.g., 0.7)
        if self.size / self.capacity > 0.7:
            self._resize()

    def remove(self, item):
        index = self._hash(item) % self.capacity
        if self.table[index] is not None:
            if isinstance(self.table[index], list):
                try:
                    self.table[index].remove(item)
                    if len(self.table[index]) == 0:
                        self.table[index] = None  # Clean up empty list
                    self.size -= 1
                    return
                except ValueError:
                    pass  # Item not found in the list
            elif self.table[index] == item:
                self.table[index] = None
                self.size -= 1
                return

    def _hash(self, item):
        return hash(item)

    def _resize(self):
        old_capacity = self.capacity
        old_table = self.table
        self.capacity *= 2
        self.table = [None] * self.capacity
        self.size = 0

        for i in range(old_capacity):
            if old_table[i] is not None:
                if isinstance(old_table[i], list):
                    for item in old_table[i]:
                        self.add(item)
                else:
                    self.add(old_table[i])

